encoded = (
    decompress(b85decode(data), format=FORMAT_RAW, filters=[{"id": FILTER_LZMA2}])
    .decode("utf-8")
    .split("\n")
)

word_set = set()
prefix_set = set()
prev = ""
for token in encoded:
    if not token:
        continue

    w = prev[: ord(token[0]) - 32] + token[1:]
    word_set.add(w)
    prev = w

    for i in range(1, len(w) + 1):
        prefix_set.add(w[:i])

board = [list(input().split()) for _ in range(5)]
visited = [[False] * 5 for _ in range(5)]

dx = [-1, -1, -1, 0, 1, 1, 1, 0]
dy = [-1, 0, 1, 1, 1, 0, -1, -1]

found = set()


def dfs(x, y, current):
    if current not in prefix_set:
        return

    if current in word_set:
        found.add(current)

    for i in range(8):
        nx, ny = x + dx[i], y + dy[i]
        if 0 <= nx < 5 and 0 <= ny < 5 and not visited[nx][ny]:
            visited[nx][ny] = True
            dfs(nx, ny, current + board[nx][ny])
            visited[nx][ny] = False


for i in range(5):
    for j in range(5):
        visited[i][j] = True
        dfs(i, j, board[i][j])
        visited[i][j] = False

print(len(found))